
local textToCopy = "https://discord.gg"
local duration = 3 
local TweenService = game:GetService("TweenService")

local notificationGui = Instance.new("ScreenGui")
notificationGui.Name = "CopyNotification"
notificationGui.ResetOnSpawn = false
notificationGui.Parent = (gethui and gethui()) or game:GetService("CoreGui") 

local frame = Instance.new("Frame")
frame.Size = UDim2.new(0.2, 0, 0.08, 0) 

frame.AnchorPoint = Vector2.new(1, 1)
frame.Position = UDim2.new(1.2, 0, 0.95, 0)

frame.BackgroundColor3 = Color3.fromRGB(30, 30, 30) 
frame.BorderSizePixel = 0
frame.Parent = notificationGui

local uiCorner = Instance.new("UICorner")
uiCorner.CornerRadius = UDim.new(0, 10)
uiCorner.Parent = frame

local label = Instance.new("TextLabel")
label.Size = UDim2.new(1, 0, 1, 0)
label.BackgroundTransparency = 1
label.Text = "Copied Discord link to clipboard!"
label.TextColor3 = Color3.fromRGB(255, 255, 255)
label.TextScaled = true
label.Font = Enum.Font.GothamBold
label.Parent = frame

if setclipboard then
    setclipboard(textToCopy)
else
    label.Text = "Clipboard not supported"
end

local tweenInfo = TweenInfo.new(0.5, Enum.EasingStyle.Quad, Enum.EasingDirection.Out)

local goalIn = {Position = UDim2.new(0.98, 0, 0.95, 0)}
local tweenIn = TweenService:Create(frame, tweenInfo, goalIn)
tweenIn:Play()

task.delay(duration, function()
    local goalOut = {Position = UDim2.new(1.2, 0, 0.95, 0)}
    local tweenOut = TweenService:Create(frame, tweenInfo, goalOut)
    tweenOut:Play()
    tweenOut.Completed:Connect(function()
        notificationGui:Destroy()
    end)
end)

